mapper.select:
/* FathMapper.selectFathSelfUrl */
SELECT  URL
        ,TO_CHAR(EXPIR_DT, 'YYYY-MM-DD HH24:MI:SS') AS expirDt
FROM    NMCP_FATH_SELF_URL@DL_MCP
WHERE   RES_NO = #{resNo}
AND     EXPIR_DT  >   SYSDATE  /*유효기간이 남아있는 경우*/

mapper.update:
/* FathMapper.updateFathMobile */
UPDATE  NMCP_CUST_REQUEST_NAME_CHG@DL_MCP
SET     FATH_TEL_NO         = #{smsRcvTelNo},
        RVISN_ID  		    = #{sessionUserId},
        RVISN_DTTM          = SYSDATE
WHERE 	MCN_RES_NO          = #{resNo}

/* FathMapper.updateFathTrgYn */
UPDATE  MCP_REQUEST@DL_MCP
SET     FATH_TRG_YN     = #{fathTrgYn},
        RVISN_ID  		= #{sessionUserId},
        RVISN_DTTM      = SYSDATE
WHERE 	RES_NO = #{resNo}

/* FathMapper.updateSelfCertType */
UPDATE  MCP_REQUEST_CSTMR@DL_MCP
SET     SELF_CERT_TYPE  = #{selfCertType},
        RVISN_ID  		= #{sessionUserId},
        RVISN_DTTM      = SYSDATE
WHERE 	REQUEST_KEY = #{requestKey}

/* FathMapper.updateSelfCertTypeMinor */
UPDATE  MCP_REQUEST_AGENT@DL_MCP
SET     MINOR_SELF_CERT_TYPE  = #{minorSelfCertType},
        RVISN_ID  		= #{sessionUserId},
        RVISN_DTTM      = SYSDATE
WHERE 	REQUEST_KEY = #{requestKey}

/* FathMapper.updateNameChgSelfCertType */
UPDATE  NMCP_CUST_REQUEST_NAME_CHG@DL_MCP
SET     SELF_CERT_TYPE  = #{selfCertType},
        RVISN_ID  		= #{sessionUserId},
        RVISN_DTTM      = SYSDATE
WHERE   MCN_RES_NO      = #{mcnResNo}

/* FathMapper.updateFathCmpltNtfyDt */
UPDATE  MCP_REQUEST@DL_MCP
SET     FATH_CMPLT_NTFY_DT  = #{fathCmpltNtfyDt},
        RVISN_ID  		    = #{sessionUserId},
        RVISN_DTTM          = SYSDATE
WHERE 	RES_NO = #{resNo}

/* FathMapper.updateReqStateCode */
UPDATE  MCP_REQUEST@DL_MCP
SET     REQUEST_STATE_CODE = #{requestStateCode},
        RVISN_ID  		= #{sessionUserId},
        RVISN_DTTM      = SYSDATE
WHERE 	RES_NO = #{resNo}

mapper.select:
/*FathMapper.selectAcenEvntType*/
SELECT  EVNT_TYPE
FROM    NMCP_ACEN_REQ@DL_MCP
WHERE   RES_NO = #{resNo}
AND     END_STATUS != 'Y'
AND     REQ_STATUS = 'N'

mapper.update:
/* FathMapper.updateNameChgInfo */ UPDATE NMCP_CUST_REQUEST_NAME_CHG@DL_MCP SET
FATH_TRG_YN = #{fathTrgYn}, MCN_STATE_CODE = '01',
FATH_TRANSAC_ID = #{fathTransacId}, CLAUSE_FATH_FLAG = #{clauseFathFlag}, MCN_STATE_CODE = '02',
FATH_CMPLT_NTFY_DT = #{fathCmpltNtfyDt}, MCN_STATE_CODE = '03',
RVISN_ID = #{sessionUserId}, RVISN_DTTM = SYSDATE WHERE MCN_RES_NO = #{mcnResNo}

/* FathMapper.updateNameChgInfoFathSkip */
UPDATE NMCP_CUST_REQUEST_NAME_CHG@DL_MCP SET
MCN_STATE_CODE = '08',
RVISN_ID = #{sessionUserId},
RVISN_DTTM = SYSDATE
WHERE MCN_RES_NO = #{mcnResNo}
